-- ============================================================
-- Booklesss — Corporate Finance / BBA 1110 partial content seed
-- Run in Supabase SQL Editor AFTER seed_lessons_steps.sql.
--
-- Populates the `content` JSONB for the 3 steps already built to v2
-- standard across these two courses: Corporate Finance Steps 1.1 and 1.2
-- (Schools/ZCAS/Corporate Finance/01-investment/sources/build_cf_1_1_*.py,
-- build_cf_1_2_*.py) and BBA 1110 Step 1.1
-- (Schools/UNZA/BBA 1110.../01-foundations/sources/build_bba_1_1_*.py).
--
-- The remaining 8 CF steps and 8 BBA steps have no PDF built yet — their
-- lesson/step skeleton rows exist (seed_lessons_steps.sql) with
-- `content = null`, and the lesson page shows a "Coming Soon" placeholder
-- until they are written (via step-skill) and this file is extended.
--
-- Tables and formula boxes from the PDFs are folded into readable prose
-- in `body` since the StepContent JSON schema (platform/lib/types.ts) has
-- no table/formula type. Inline PDF markup (<b>, <i>, <br/>) is stripped
-- since LessonContent.tsx renders section body as plain text, not HTML.
-- ============================================================

update steps set content = '{"sections": [{"eyebrow": "START HERE", "heading": "You''re Running the Money for Your Own Company", "body": "Read this the way a founder reads it. You are not studying some distant corporation — you are the person who decides where your company''s cash goes. Every tool in this step answers a question you will actually face: is this worth my money, and can I prove it before I commit a single coin?\n\nThis is the first step in Lesson 1 — Investment Appraisal. You''ll value projects the way a finance team actually values them: in cash, discounted to today, with a clear rule for when to say yes and when to walk away. Everything in Lesson 2 onwards leans on the machinery you build here, so it''s worth slowing down.", "callout": {"label": "Fact", "body": "Everything that follows is built on this step. NPV, free cash flow, and discounting reappear in every step after it — master them here and the rest of the course is depth, not new ground."}}, {"eyebrow": "CONCEPT 01", "heading": "Free Cash Flow — What Your Company Actually Earns", "body": "Every investment decision starts with one question: how much cash will this actually produce? Not accounting profit — cash. Profit is what the income statement shows after adjustments for depreciation, accruals, and timing. Cash is what lands in your account.\n\nFree cash flow (FCF) is the cash left after your company has covered its operating costs, paid tax, and reinvested what it needs to keep running and growing. It belongs to everyone who put capital in — both debt holders and shareholders.\n\nFCF to the firm is the total cash the business generates for everyone who funded it, before any of them are paid: start with net operating profit (PBIT), add back depreciation (non-cash), deduct taxation, then subtract replacement of non-current assets, incremental non-current assets, and incremental working capital. What remains is free cash flow to the firm.\n\nFCF to equity takes that figure and subtracts debt interest paid and loan repayments, then adds any new debt raised — what remains belongs to shareholders.\n\nWorked example — Zambeef Processing Division (ZMW ''000): operating profit (PBIT) 300, plus depreciation 120, less tax paid (140), less replacement capex (10), less new investment capex (15), less increase in working capital (50). FCF to the firm = 300 + 120 − 140 − 10 − 15 − 50 = ZMW 205,000. Deduct interest paid (5) and loan repaid (20): FCF to equity = 205 − 5 − 20 = ZMW 180,000.", "callout": {"label": "Fact", "body": "Free cash flow is what remains after the company has kept running, replaced its assets, and funded its growth — it is what actually belongs to investors, not the profit number on the income statement."}}, {"eyebrow": "CONCEPT 02", "heading": "Net Present Value — The Right Way to Say Yes or No", "body": "Your company is deciding whether to invest ZMW 24,000 in a new distribution route generating cash for five years. The question is not whether total cash in exceeds ZMW 24,000 — it''s whether those future cash flows are worth ZMW 24,000 today. Money received in the future is worth less than money today, because money now could be invested and earn a return. NPV accounts for this by discounting all future cash flows back to today''s value using a discount factor of 1/(1+r)^n.\n\nWorked example — distribution project at a 10% cost of capital: Year 0 outflow (24,000); Year 1 inflow 7,800, present value 7,090; Year 2 inflow 6,000, present value 4,956; Year 3 inflow 4,200, present value 3,154; Year 4 inflow 7,400, present value 5,054; Year 5 inflow 9,200, present value 5,713. NPV = ZMW 1,967. The project creates ZMW 1,967 of value in today''s money, above and beyond recovering the investment and earning the required 10% return. Accept it.", "callout": {"label": "Fact", "body": "A positive NPV means today''s value of future earnings exceeds the cost of the investment — the project creates wealth for your company. Rule: NPV > 0, accept; NPV < 0, reject."}}, {"eyebrow": "CONCEPT 03", "heading": "Discounted Payback — When Do You Get Your Money Back?", "body": "Discounted payback period (DPP) is how long it takes for the cumulative present value of cash inflows to recover the initial investment — a stricter version of simple payback that accounts for the time value of money. Using the same ZMW 24,000 distribution project, the cumulative present value turns positive during Year 5: after Year 4 the shortfall is ZMW 3,746, and Year 5 brings in a present value of ZMW 5,713. DPP = 4 + (3,746/5,713) = 4.66 years. If the target payback is 4 years, this project does not meet it — even though it still has a positive NPV. DPP and NPV can conflict.", "callout": {"label": "Fact", "body": "Discounted payback tells you when you recover your investment in real terms — use it as a liquidity check, not as the main decision rule. A project can miss the payback target and still be worth doing."}}, {"eyebrow": "CONCEPT 04", "heading": "Internal Rate of Return — The Break-Even Discount Rate", "body": "The internal rate of return (IRR) is the discount rate that makes NPV equal to zero — the rate your project earns on the capital tied up in it. If your company''s cost of capital is 10% and the project earns 13%, it clears the hurdle. IRR is found by interpolation: calculate NPV at two different discount rates, one positive and one negative, then estimate where NPV crosses zero, using IRR = A + [a / (a − b)] × (B − A).\n\nWorked example — same ZMW 24,000 project: NPV at 10% is 1,967, NPV at 14% is (554). IRR = 10% + [1,967 / (1,967 + 554)] × 4% = 10% + 3.12% = 13.12%. Since IRR (13.12%) exceeds the cost of capital (10%), accept.\n\nIRR has two problems in practice. Multiple IRRs: if a project''s cash flows change sign more than once, there can be two or more IRRs and the accept/reject rule breaks down. Unrealistic reinvestment assumption: IRR assumes every kwacha generated is reinvested at the IRR itself — for a 13% IRR project, that means finding 13% returns for reinvested cash throughout the project life, which is almost never possible. NPV avoids this by assuming reinvestment at the cost of capital.", "callout": {"label": "Fact", "body": "IRR tells you the break-even discount rate — not the actual return — unless cash flows can genuinely be reinvested at that same rate throughout the project. In most real projects, they cannot."}}, {"eyebrow": "CONCEPT 05", "heading": "Modified IRR — A More Honest Return", "body": "MIRR fixes IRR''s reinvestment problem by separating the two rates: your cost of capital for outflows, and a realistic reinvestment rate for inflows. MIRR = the nth root of (FVCF / PVCF) minus 1, where FVCF is the future value of inflows compounded at the reinvestment rate, PVCF is the present value of outflows discounted at cost of capital, and n is the project life.\n\nWorked example — same ZMW 24,000 project, cost of capital 10%, reinvestment rate 12%. Compounding each inflow to Year 5 at 12% gives a total future value of cash flows of ZMW 43,459. MIRR = fifth root of (43,459 / 24,000) minus 1 = 1.1260 − 1 = 12.6%. Since MIRR (12.6%) exceeds the cost of capital (10%), the project is acceptable. Compare: IRR was 13.12% — MIRR gives the lower, more honest figure, since IRR overstated the return by assuming 13.12% reinvestment.", "callout": {"label": "Fact", "body": "MIRR replaces IRR''s impossible reinvestment assumption with a rate you actually expect to earn — giving a more accurate picture of what the project truly returns to your business."}}, {"eyebrow": "CONCEPT 06", "heading": "Inflation and Tax — Two Adjustments You Cannot Skip", "body": "Inflation affects both cash flows and discount rates, and can be handled two ways that give the same NPV when done correctly. The nominal method inflates each cash flow at its specific rate, then discounts at the nominal cost of capital — use this when different items inflate at different rates (wages at 8%, raw materials at 5%, selling prices at 6%). The real method strips inflation from cash flows and discounts at the real rate — only works when everything inflates uniformly. The Fisher equation links the two: (1 + nominal rate) = (1 + real rate) × (1 + inflation rate). Example: real rate 5%, inflation 8% gives a nominal rate of (1.05 × 1.08) − 1 = 13.4%.\n\nTax affects appraisal in two ways. First, the company pays tax on operating cash flows — an outflow that reduces FCF. Second, tax allowable depreciation (capital allowances) reduces taxable profit, generating a tax saving that acts as a cash inflow. Always include both: tax on operating cash flows as an outflow, and the tax saving from capital allowances as an inflow — leaving either out gives the wrong NPV.", "callout": {"label": "Fact", "body": "Tax on operating flows reduces your FCF. Capital allowances reduce your tax bill. Both are real cash movements and both change the NPV of a project."}}], "discussionQuestions": ["Your company is comparing two projects. Project A: NPV of ZMW 1,967, requires ZMW 24,000. Project B: NPV of ZMW 1,400, requires ZMW 10,000. You can only fund one. Which do you choose — and does the answer change if you have ZMW 50,000 available? What does your decision reveal about how you think about allocating capital inside the business?", "First Quantum is evaluating a ZMW 3 million processing upgrade. Cash flows: ZMW 600,000 in Year 1, increasing by ZMW 160,000 each year for five more years. The cost of capital is 21% and the reinvestment rate is 8%. Would you calculate IRR or MIRR first — and why does the gap between those two rates matter more for a long-horizon project than a short one?"], "keyTerms": [{"term": "Free Cash Flow (FCF)", "definition": "Cash available after operating costs, tax, and reinvestment in working capital and fixed assets"}, {"term": "FCF to the Firm", "definition": "FCF available to all providers of capital — debt holders and equity holders"}, {"term": "FCF to Equity", "definition": "FCF remaining for shareholders after interest and loan repayments"}, {"term": "PBIT", "definition": "Profit before interest and tax — the starting point for FCF calculation"}, {"term": "Net Present Value (NPV)", "definition": "Sum of all discounted future cash flows minus the initial investment"}, {"term": "Discount Factor", "definition": "Multiplier that converts a future cash flow to present value: 1 / (1+r)^n"}, {"term": "Discounted Payback Period (DPP)", "definition": "Time to recover the initial investment using present-value cash flows"}, {"term": "Internal Rate of Return (IRR)", "definition": "The discount rate at which NPV = 0; the project''s break-even rate"}, {"term": "Modified IRR (MIRR)", "definition": "IRR recalculated using a realistic reinvestment rate, giving a more accurate return figure"}, {"term": "Reinvestment Rate", "definition": "The rate at which interim cash flows are actually expected to be reinvested; used in MIRR"}, {"term": "Cost of Capital", "definition": "The required return used as the discount rate; derived from WACC/CAPM"}, {"term": "Nominal Rate", "definition": "The stated rate, including inflation"}, {"term": "Real Rate", "definition": "The rate adjusted for inflation"}, {"term": "Fisher Equation", "definition": "(1 + nominal) = (1 + real) x (1 + inflation) — links the three rates"}, {"term": "Capital Allowance", "definition": "Tax-deductible depreciation that generates a tax saving on investments"}, {"term": "RAI / IAI / IWCI", "definition": "Replacement assets / Incremental assets / Incremental working capital — the three investment deductions in FCF"}], "learningOutcomes": ["Calculate free cash flow to the firm and free cash flow to equity from accounting data", "Apply the NPV decision rule and explain in plain terms what a positive NPV means", "Calculate the discounted payback period and identify when it conflicts with NPV", "Compute IRR by linear interpolation and apply the accept/reject rule", "Explain the two main limitations of IRR: multiple IRRs and the reinvestment assumption", "Calculate MIRR and explain why it gives a more accurate return figure than IRR", "Handle inflation in NPV analysis using both the nominal and real methods", "Identify the two ways tax affects appraisal: tax on operating flows and capital allowance savings"]}'::jsonb
where slug = 'investment-fundamentals'
  and lesson_id = (select id from lessons where slug = 'investment' and course_id = (select id from courses where slug = 'corporate-finance'));

update steps set content = '{"sections": [{"eyebrow": "START HERE", "heading": "Same Company, Two New Pressures", "body": "Keep reading as the founder. In Step 1.1 you valued projects as if your company paid for everything out of its own pocket — all equity, no borrowing, and enough money to fund every project that cleared the hurdle. That kept the maths clean while you learned NPV, IRR, and MIRR.\n\nReal companies don''t run that way. You borrow to fund big projects, and borrowing changes the value of the deal because interest is tax-deductible. And you almost never have enough cash to back every project with a positive NPV at once. This step handles both pressures: APV values a project and its financing separately, and capital rationing tells you which projects to pick when the money runs out.", "callout": {"label": "Fact", "body": "Everything here is built on Step 1.1. APV is just NPV done twice — once for the project, once for the financing — and capital rationing is NPV ranked under a budget. The discounting machinery does not change."}}, {"eyebrow": "CONCEPT 01", "heading": "Where Basic NPV Runs Out of Road", "body": "In Step 1.1 you discounted free cash flows at a single cost of capital and accepted any project with a positive NPV. That single rate quietly assumes the project is financed the same way as the rest of the company, and the company''s mix of debt and equity stays put.\n\nTwo situations break that assumption. First, a project financed mostly by a new loan changes how much debt the company carries. Second, the financing itself creates value the project''s cash flows never show: interest on debt is tax-deductible, so borrowing hands you a tax saving, while raising the money costs fees.\n\nAdjusted present value (APV) fixes this by refusing to mix the two questions. It values the project as if it were all-equity financed, then values the financing side effects separately, and adds them. You see exactly how much of the deal''s worth comes from the project and how much from the way you paid for it.", "callout": {"label": "Fact", "body": "Use APV when the financing changes the company''s debt level or has its own cash effects (tax shields, issue costs, subsidised loans). When financing is just the company''s normal mix, ordinary NPV is enough."}}, {"eyebrow": "CONCEPT 02", "heading": "Adjusted Present Value — Project First, Financing Second", "body": "APV splits the value of a geared (debt-financed) project into two parts calculated separately: APV = base-case NPV + PV of financing side effects. Base-case NPV is the project valued as if it were 100% equity financed. Financing effects are the tax shield on debt interest, less the cost of raising the finance.\n\nThe base-case NPV is the investment decision on its own — discount the project''s free cash flows at the ungeared (unlevered) cost of equity, Ku, the return equity investors would want if the project carried no debt at all. That rate reflects only business risk, not financing risk.\n\nThe financing side effects are the financing decision on its own, discounted at the cost of debt (or risk-free rate) since both are low-risk and predictable. Interest tax shield: interest on debt is tax-deductible, so each year''s interest saves (interest x tax rate) in tax — a real cash inflow, add its present value. Issue costs: raising debt or equity costs fees, a real cash outflow — subtract it. Issue costs of debt are tax-deductible; issue costs of equity are not.\n\nThe APV layout: base-case NPV (discounted at Ku), minus present value of issue costs, plus present value of interest tax shield, equals adjusted present value. Decision rule: accept the project if APV is positive.", "callout": {"label": "Fact", "body": "APV = the project''s value if all-equity financed, plus the value the financing adds (tax shield) minus what it costs (issue fees). It keeps the investment decision and the financing decision in separate columns."}}, {"eyebrow": "CONCEPT 03", "heading": "Issue Costs and Grossing Up", "body": "One detail trips students up every year: when finance has issue costs, the amount you raise has to cover both the project and the fees. If you need a clean ZMW 2.4 million in hand and the issuer charges 4% of the total raised, you cannot just raise ZMW 2.4 million — the fee comes out of it and leaves you short.\n\nSo you gross up. The ZMW 2.4 million you actually need is 96% of the gross amount (since 4% is eaten by fees): gross amount to raise = net needed / (1 − issue cost %) = 2,400,000 / 0.96 = ZMW 2,500,000. Issue cost = 2,500,000 x 4% = ZMW 100,000 (or in one step, 2,400,000 x 4/96 = ZMW 100,000).\n\nIn an APV, the issue cost is the figure you subtract. If the cost relates to debt, it is tax-deductible, so use the after-tax figure: a gross debt issue cost of ZMW 338.60 at a 30% tax rate is 338.60 x (1 − 0.30) = ZMW 237 after tax. An equity issue cost gets no such relief — subtract it in full.", "callout": {"label": "Fact", "body": "Gross up so the cash you raise still covers the project after fees. Then carry debt issue costs into the APV net of tax, and equity issue costs in full."}}, {"eyebrow": "CONCEPT 04", "heading": "APV End to End — Mutengo Mills", "body": "Mutengo Mills is appraising a new milling line. The ungeared cost of equity is 10%. The line will be part-funded by a ZMW 6,000,000 bank loan at 8% interest, repaid in equal instalments of ZMW 1,500,000 a year over four years. Tax is 30%, and the gross issue cost of the debt is ZMW 338,600.\n\nStep 1 — base-case NPV, discounting the project''s cash flows (in ZMW ''000: outflow 10,000 at Year 0; inflows 1,500, 2,500, 4,500, 5,000 in Years 1-4) at Ku = 10% gives a base-case NPV of ZMW 224,000. On its own, the project is barely worth doing.\n\nStep 2 — PV of the interest tax shield, discounted at the 8% cost of debt. The loan is repaid ZMW 1,500,000 a year, so the balance and interest fall each year: interest is 8% of the opening balance, the tax shield is 30% of that interest. Summing the discounted shields across the four years gives a present value of interest tax shield (PVITS) of ZMW 309,000.\n\nStep 3 — issue cost, net of tax: the gross debt issue cost of ZMW 338,600 is tax-deductible, so the after-tax cost is 338,600 x (1 − 0.30) = ZMW 237,000.\n\nStep 4 — assemble the APV: base-case NPV 224,000, minus PV of debt issue cost after tax (237,000), plus PV of interest tax shield 309,000, equals APV of ZMW 296,000. The APV is comfortably positive, and noticeably better than the ZMW 224,000 base case. The extra ZMW 72,000 is the net gift of the financing — a ZMW 309,000 tax shield on the borrowed money, less the ZMW 237,000 cost of raising it.", "callout": {"label": "Fact", "body": "APV here = 224 − 237 + 309 = ZMW 296,000. A project that looked weak on its cash flows alone becomes a clear accept once the tax shield on its debt is counted. That is exactly the value ordinary NPV would have hidden."}}, {"eyebrow": "CONCEPT 05", "heading": "Capital Rationing — Choosing When You Can''t Fund Everything", "body": "APV told you whether one project is worth doing. Capital rationing answers a different question: you have several projects that each clear the hurdle, but not enough money to back them all. Which combination do you choose?\n\nFirst, name the constraint. Hard rationing is external — the bank simply won''t lend you more, at any price. Soft rationing is self-imposed — your board has capped this year''s investment budget to keep control, even though more finance is available. The maths is the same; the cause is what differs.\n\nWhen the shortage is in one period only, you want the most NPV per kwacha invested, not just the biggest NPV. The tool is the profitability index (PI) = PV of future cash flows / initial investment. PI greater than 1 means the project''s inflows are worth more than its cost. Rank projects by PI, then take them in order until the budget runs out.\n\nWorked example — Mutengo has ZMW 5,000,000 to invest this year across four divisible projects: Project A (outlay 2,000,000, NPV 600,000, PI 1.30, rank 1), Project B (outlay 1,000,000, NPV 250,000, PI 1.25, rank 2), Project C (outlay 1,500,000, NPV 300,000, PI 1.20, rank 3), Project D (outlay 2,500,000, NPV 250,000, PI 1.10, rank 4). Taking A, B, and C in full uses ZMW 4,500,000, leaving ZMW 500,000 — 20% of Project D. Total NPV captured = 600,000 + 250,000 + 300,000 + (20% x 250,000) = ZMW 1,200,000. Notice D is taken last and only partly, even though its NPV (250,000) ties B''s, because each kwacha put into D works less hard. Highest NPV is not the same as best use of a tight budget.\n\nThe PI ranking works cleanly only when projects are divisible. If they are all-or-nothing (indivisible), you cannot take a fraction of a project — instead you test whole combinations that fit the budget and pick the one with the highest combined NPV.", "callout": {"label": "Fact", "body": "Under a single-period budget, rank by profitability index, not by NPV. PI measures value created per kwacha invested — exactly what you are short of."}}, {"eyebrow": "CONCEPT 06", "heading": "Multi-Period Rationing — When the Budget Bites Every Year", "body": "The profitability index works for one tight year. But suppose the budget is limited in several years at once, and projects draw on those budgets in different amounts each year. A simple ranking can''t juggle several constraints together — you need linear programming to find the mix that maximises total NPV while staying inside every annual limit.\n\nWorked example — Kabwe Holdings has approved budgets of ZMW 16,000,000 (Year 1), ZMW 14,000,000 (Year 2), and ZMW 17,000,000 (Year 3) across four projects with project NPVs of 8,000, 11,000, 6,000, and 4,000 (ZMW ''000). Letting x1 to x4 be the proportion of each project undertaken (0 to 1), the problem maximises total NPV subject to each year''s budget constraint. Solved by linear programming, the optimum is to take Projects 1 and 2 in full and drop 3 and 4, giving total NPV = 8,000 + 11,000 = ZMW 19,000,000.\n\nProjects 3 and 4 also fit inside the budgets, but their combined NPV is only ZMW 10,000,000 — well below 19,000,000. The constraints alone don''t pick the winner; the objective function does. If projects must be whole rather than fractional, the same setup becomes integer programming, forcing each x to be 0 or 1.", "callout": {"label": "Fact", "body": "When budgets bind in more than one period, linear programming maximises total NPV across all the constraints at once. Fitting the budget is necessary but not sufficient — the best feasible mix is the one with the highest combined NPV."}}], "discussionQuestions": ["Your company can fund a ZMW 10 million expansion two ways: entirely from retained earnings, or by borrowing ZMW 6 million at 8% and putting in ZMW 4 million of equity. The base-case NPV is identical either way. Using APV thinking, why is the borrowed route worth more to your shareholders — and what single change to Zambia''s tax rules would make that advantage vanish completely?", "You rank four divisible projects by profitability index and the budget runs out part-way through the fourth. A colleague says you should instead just pick the three projects with the highest individual NPVs. Build your own small numerical example where the two methods disagree — and explain which one actually maximises the value created from a fixed pot of cash, and why."], "keyTerms": [{"term": "Adjusted Present Value (APV)", "definition": "Project value split into base-case (all-equity) NPV plus the PV of financing side effects"}, {"term": "Base-case NPV", "definition": "The project valued as if 100% equity financed, discounting cash flows at the ungeared cost of equity"}, {"term": "Ungeared cost of equity (Ku)", "definition": "The return equity investors require with no debt in place; reflects business risk only"}, {"term": "Financing side effects", "definition": "Cash effects created by how a project is funded — chiefly the interest tax shield and issue costs"}, {"term": "Interest tax shield", "definition": "The tax saved because debt interest is tax-deductible: interest x tax rate, each period"}, {"term": "Issue costs", "definition": "Fees paid to raise finance. Debt issue costs are tax-deductible; equity issue costs are not"}, {"term": "Grossing up", "definition": "Scaling the amount raised so it still covers the project after issue fees: net / (1 minus fee %)"}, {"term": "Capital rationing", "definition": "Having more positive-NPV projects than money to fund them"}, {"term": "Hard rationing", "definition": "External limit — lenders will not advance more finance at any price"}, {"term": "Soft rationing", "definition": "Internal limit — management caps the investment budget by choice"}, {"term": "Profitability Index (PI)", "definition": "PV of future cash flows divided by initial investment; ranks projects by value created per kwacha"}, {"term": "Divisible project", "definition": "A project that can be part-funded, taking a fraction of it for a proportional share of NPV"}, {"term": "Single-period rationing", "definition": "Budget binds in one period only; solved by ranking on the profitability index"}, {"term": "Multi-period rationing", "definition": "Budget binds in several periods; solved by linear (or integer) programming"}, {"term": "Objective function", "definition": "The quantity an LP maximises — here, total NPV across the chosen projects"}], "learningOutcomes": ["Explain why a single discount rate breaks down when a project changes the firm''s financing, and when to switch to APV", "Set out the APV structure: base-case NPV plus the PV of financing side effects", "Calculate a base-case NPV by discounting project cash flows at the ungeared cost of equity (Ku)", "Calculate the present value of an interest tax shield on a repaying loan, discounted at the cost of debt", "Gross up for issue costs and carry debt issue costs into an APV net of tax", "Assemble a full APV and apply the accept-if-positive decision rule", "Distinguish hard from soft capital rationing", "Rank and select divisible projects under a single-period budget using the profitability index", "Recognise when multi-period rationing requires linear programming and set up the objective function and constraints"]}'::jsonb
where slug = 'advanced-investment'
  and lesson_id = (select id from lessons where slug = 'investment' and course_id = (select id from courses where slug = 'corporate-finance'));

update steps set content = '{"sections": [{"eyebrow": "CONCEPT 01", "heading": "What Is Business?", "body": "A business is any organisation that transforms resources — land, labour, and capital — into goods or services that satisfy the wants of buyers. The transformation adds value: the finished output is worth more than the inputs consumed to produce it. That margin, when positive and sustained, is profit.\n\nBusiness administration is the systematic management of how that transformation happens: planning what to produce, organising the people and resources required, directing the work, and controlling the outcome against the plan. These four activities — plan, organise, direct, control — reappear in every topic of this course.\n\nBusinesses are classified by the sector of the economy they operate in. Primary sector: extraction of raw materials directly from nature — copper mining (ZCCM-IH, First Quantum Minerals), maize farming, fishing. Secondary sector: processing or manufacturing raw materials into finished goods — Zambeef processing livestock, Zambia Sugar refining cane, National Breweries. Tertiary sector: providing services rather than physical goods — Zanaco (banking), MTN Zambia (telecoms), ZESCO (electricity distribution).", "callout": {"label": "Fact", "body": "Every organisation — whether a roadside Kantemba or First Quantum Minerals — performs the same four management functions. The scale changes; the logic does not."}}, {"eyebrow": "CONCEPT 02", "heading": "Types of Business Organisation", "body": "The legal form a business takes determines who owns it, who is liable for its debts, how it raises capital, and how it is controlled. Five forms appear on every exam.\n\nSole Trader: owned and managed by one person, simplest to set up, all profit belongs to the owner. Liability is unlimited — personal assets at risk. Example: a roadside Kantemba stall, a freelance accountant.\n\nPartnership: 2-20 owners share capital, profit, loss, and management, governed by a partnership deed. Liability is unlimited for ordinary partners. Example: a law firm or medical practice with shared ownership.\n\nPrivate Limited Company (Ltd): a separate legal entity — shareholders own it, directors manage it, shares are not publicly traded. Liability is limited to share value. Example: most Zambian SMEs registered as private companies.\n\nPublic Limited Company (PLC): shares traded on a public stock exchange, able to raise large capital from the public. Liability is limited to share value. Example: Zambeef Products PLC on the Lusaka Securities Exchange (LuSE).\n\nPublic Sector Organisation: owned by government on behalf of citizens, with an objective of service delivery rather than profit. Government backed. Example: ZESCO (national electricity utility), University of Zambia.", "callout": {"label": "Limited Liability", "body": "In a sole proprietorship or general partnership, the owner''s personal assets — home, car, savings — can be seized to settle business debts. Incorporation creates a legal barrier between the individual and the firm. That protection is what drives most businesses to incorporate as they grow."}}, {"eyebrow": "CONCEPT 03", "heading": "What Businesses Exist to Achieve", "body": "An objective is a specific, measurable target that directs the organisation''s decisions. Different ownership structures produce different objectives — and within a single firm, objectives evolve as the business moves through its life stages.\n\nProfit maximisation: generate the highest possible surplus of revenue over costs. Prioritised by shareholders in listed PLCs and sole traders with no growth ambition.\n\nSatisficing: earn enough profit to satisfy shareholders while pursuing other goals — not maximum profit, sufficient profit. Prioritised by owner-managers balancing profit with work-life balance or social aims.\n\nSurvival: remain solvent during a downturn, new competition, or startup phase — revenue covers costs, cash flow is positive. Prioritised by new businesses and firms under financial stress.\n\nGrowth: increase revenue, market share, or geographic reach, often at the expense of short-run profit. Prioritised by businesses reinvesting to scale, e.g. Shoprite expanding into new regions.\n\nSocial/ethical: serve community needs, minimise harm, operate sustainably — profit is a constraint, not the goal. Prioritised by public sector bodies, cooperatives, NGOs, B-Corp certified firms.\n\nZESCO illustrates why sector matters. As a state-owned utility, ZESCO''s primary objective is reliable electricity supply to households and industry across Zambia — including rural areas where it would never be profitable to operate. A private company serving the same market would exit the unprofitable routes. Government ownership keeps those routes open because the social objective overrides profit.", "callout": {"label": "Fact", "body": "Objectives are not fixed. A business that survives its startup phase shifts to growth. A growth-focused firm that faces a recession shifts to survival. Reading which objective applies in a case question is half the analytical work."}}, {"eyebrow": "CONCEPT 04", "heading": "Who Has a Stake?", "body": "A stakeholder is any individual or group affected by the organisation''s activities — or whose actions can affect the organisation. Stakeholders are not all equal: some can shut the business down (government, banks), others can only complain (local residents).\n\nShareholders/owners: want profit and capital growth, may demand short-run profits that sacrifice long-run investment.\nEmployees: want job security, fair wages, safe conditions, career development; wage increases reduce profit available for shareholders.\nCustomers: want quality goods and services at fair prices; lower prices cut margins, quality improvements raise costs.\nSuppliers: want prompt payment, long-term contracts, fair terms; the firm may delay payment or switch to cheaper suppliers.\nGovernment: wants tax revenue, employment, legal compliance, economic development; regulations and taxes constrain business decisions.\nLocal community: wants employment, minimal environmental harm, contribution to the local economy; expansion may bring noise, pollution, or traffic.\nLenders (banks): want interest payments and return of principal, low default risk; debt obligations constrain cash flow and limit strategic flexibility.\n\nStakeholder conflicts are resolved through negotiation, regulation, or power. Shareholders are legally the owners and take precedence in most private companies — but governments set the floor through labour law, environmental regulation, and tax codes that constrain what shareholders can demand."}], "discussionQuestions": ["Chanda runs a tailoring business from her home in Lusaka. She earns ZMW 8,000 a month and has one employee. Her sister wants to join the business, contribute ZMW 20,000 in capital, and share the profits equally. Identify the current legal form of Chanda''s business and the form it would become if the sister joins. State two advantages and one disadvantage of the new form compared to the current one.", "Zambia Sugar PLC announces plans to expand its Mazabuka estate by 3,000 hectares. The expansion will create 800 jobs but will displace 200 smallholder farming families currently leasing that land. Identify four stakeholder groups affected by this decision. For each, state their primary interest and whether it aligns with or conflicts with the expansion. Then state which stakeholder group has the most power to halt the project and why."], "keyTerms": [{"term": "Business", "definition": "An organisation that transforms land, labour, and capital into goods or services for buyers, generating value through that transformation"}, {"term": "Business Administration", "definition": "The systematic management of an organisation''s affairs: planning, organising, directing, and controlling resources to achieve objectives"}, {"term": "Primary sector", "definition": "Economic activity involving direct extraction of natural resources (mining, farming, fishing)"}, {"term": "Secondary sector", "definition": "Economic activity involving processing or manufacturing of raw materials into finished goods"}, {"term": "Tertiary sector", "definition": "Economic activity involving the provision of services rather than physical goods"}, {"term": "Sole Trader", "definition": "A business owned and managed by one person with unlimited personal liability for debts"}, {"term": "Limited Liability", "definition": "Legal protection that caps an investor''s financial loss at the value of their shareholding"}, {"term": "Objective", "definition": "A specific, measurable target that directs the decisions of an organisation"}, {"term": "Profit maximisation", "definition": "The goal of generating the highest possible surplus of revenue over total costs"}, {"term": "Satisficing", "definition": "Earning sufficient rather than maximum profit, allowing pursuit of other goals alongside profitability"}, {"term": "Stakeholder", "definition": "Any individual or group that is affected by the organisation''s activities, or whose actions can affect the organisation"}], "learningOutcomes": ["Define business and explain how it creates value through resource transformation", "Distinguish the three sectors of the economy and give a Zambian example for each", "Compare five types of business organisation, including their liability implications", "Explain why different ownership structures produce different primary objectives", "Define stakeholder, classify stakeholders as internal or external, and identify typical conflicts between them"]}'::jsonb
where slug = 'intro-to-business'
  and lesson_id = (select id from lessons where slug = 'foundations' and course_id = (select id from courses where slug = 'bba-1110'));
